document.addEventListener("DOMContentLoaded",async()=>{let ADMIN_LOGIN_API_BASE_URL=window.location.origin+"/api";var loginForm=document.getElementById("admin-login-form");let errorMessage=document.getElementById("error-message"),submitButton=loginForm.querySelector('button[type="submit"]');var existingUser=await(async()=>{var cachedUser=sessionStorage.getItem("user");if(!cachedUser)return null;try{JSON.parse(cachedUser)}catch(error){return sessionStorage.removeItem("user"),null}try{var data,response=await fetch(ADMIN_LOGIN_API_BASE_URL+"/auth/me",{credentials:"same-origin"});return response.ok?(data=await response.json(),sessionStorage.setItem("user",JSON.stringify(data.user)),data.user):(sessionStorage.removeItem("user"),null)}catch(error){return sessionStorage.removeItem("user"),null}})();existingUser&&"admin"===existingUser.role?window.location.href="admin-dashboard.html":loginForm.addEventListener("submit",async event=>{event.preventDefault();var event=document.getElementById("email").value.trim(),password=document.getElementById("password").value;if(errorMessage.textContent="",event&&password){submitButton.disabled=!0,submitButton.innerHTML='<i class="fas fa-spinner fa-spin"></i> Loggar in...';try{var response=await fetch(ADMIN_LOGIN_API_BASE_URL+"/auth/login",{method:"POST",headers:{"Content-Type":"application/json"},credentials:"same-origin",body:JSON.stringify({email:event,password:password})}),data=await response.json();response.ok?(sessionStorage.setItem("user",JSON.stringify(data.user)),window.location.href="admin-dashboard.html"):errorMessage.textContent=data.error||"Inloggning misslyckades."}catch(error){console.error("Login error:",error),errorMessage.textContent="Ett fel uppstod. Försök igen senare."}finally{submitButton.disabled=!1,submitButton.innerHTML='<i class="fas fa-sign-in-alt"></i> Logga in'}}else errorMessage.textContent="Fyll i alla fält."})});